{
  "component_diagram": {
    "control_plane": {
      "orchestrator": "Argo Workflows",
      "scheduler": "Volcano/Kueue",
      "git_ops": "ArgoCD + Kustomize",
      "artifact_store": "GCS with versioned prefixes"
    },
    "training_plane": {
      "cluster_manager": "GKE + Node Auto-provisioning",
      "gpu_scheduler": "Kueue with cohort scheduling",
      "distributed_strategy": {
        "tf": "tf.distribute.MirroredStrategy + MultiWorkerMirroredStrategy",
        "pytorch": "torch.distributed.elastic (torchelastic)"
      },
      "fault_tolerance": {
        "checkpoint": "torch.utils.checkpoint every 15 min",
        "preemption": "Spot instance draining webhook + checkpoint migration"
      }
    },
    "feature_store": {
      "online": "Redis Cluster (low-latency serving features)",
      "offline": "BigQuery + Parquet on GCS",
      "point_in_time": "Feast + Spark for temporal joins",
      "freshness_sla": "less than 30s for real-time features"
    },
    "model_registry": {
      "metadata_store": "MLMD on Cloud Spanner",
      "versioning": "Semantic (v1.2.3) + git-hash tagged",
      "lineage": "Full DAG: data source → feature → training → eval → deployment"
    },
    "serving_plane": {
      "primary": "TensorFlow Serving (TF1 models)",
      "secondary": "Triton Inference Server (ONNX/TorchScript)",
      "deployment": "Istio canary (5% → 25% → 100%)",
      "auto_scaling": "HPA based on request latency + throughput"
    },
    "observability": {
      "metrics": "Prometheus + Thanos (long-term retention)",
      "alerts": "Alertmanager with severity tiers",
      "drift_detection": "KS-test on prediction distributions, sliding 1h window",
      "cost_tracking": "GCP labels per training job, BigQuery billing export"
    }
  },
  "key_metrics": {
    "training_runs_per_day": 10000,
    "models_in_registry": 5000,
    "p99_serving_latency": "less than 50ms",
    "cold_start_time": "less than 5 min",
    "uptime_sla": "99.9%"
  }
}

{
  "preparation_checklist": {
    "week_1_2": [
      "Review ML fundamentals — write every algorithm from memory",
      "Record yourself explaining concepts out loud",
      "Read 5 ML papers (Attention Is All You Need, BatchNorm, ResNet, etc.)"
    ],
    "week_3_4": [
      "Sketch architectures for 10 common ML systems",
      "Practice trade-off discussions: batch vs real-time, deep vs shallow, etc.",
      "Study ML platform patterns (feature stores, model registries, monitoring)"
    ],
    "week_5": [
      "Implement 10 ML algorithms from scratch (30 min each)",
      "Prepare 15 behavioral stories with STAR/SIT structure",
      "Practice metric definitions: what numbers matter for each system?"
    ],
    "week_6": [
      "5+ full-length mock interviews with feedback",
      "Practice think-aloud: verbalize every thought",
      "Record and review: identify filler words, dead air, unclear sections"
    ]
  },
  "scoring_rubric": {
    "strong_hire_4": "Proactive clarification, explicit trade-offs, concrete numbers, handles follow-ups",
    "hire_3": "Good structure, covers components, reasonable trade-offs, adequate follow-ups",
    "no_hire_2": "Misses requirements, irrelevant depth, flustered",
    "strong_no_hire_1": "No coherent architecture, fundamental misunderstandings"
  },
  "company_expectations": {
    "google_l6": "Deep ML expertise + technical leadership, 6+ years experience",
    "amazon_l6": "Leadership Principles fluency, org-level impact stories",
    "meta_e6": "Cross-functional impact, shipped ML at scale, iteration speed",
    "apple_ict5": "Hardware-aware ML, performance optimization, on-device experience"
  },
  "common_pitfalls": [
    "Talking too long without pausing for feedback",
    "Vague metrics (saying faster instead of p50 less than 30ms)",
    "Ignoring failure modes and edge cases",
    "Not scoping the problem before designing",
    "Defensiveness when challenged"
  ]
}
